var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"건배애애애!","JPN":"乾杯～！","ENG":"CHEEEERS!","TWN":"乾杯～～！！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"캬아, 오늘따라 맥주 맛 한 번 끝내 주네!","JPN":"くう、今日のビールは格別にうまいな！","ENG":"Oh, man! Victory beer tastes so good!","TWN":"哈～！今天的啤酒特別好喝呢！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"너무 과음하지 마요, 라이카. 괜히 만취해서 사고치지 말고.","JPN":"飲みすぎないでよ、ライカ。酔っぱらって問題なんか起こさないように。","ENG":"Don't drink too much, Laika. Or you'll get drunk and cause trouble again.","TWN":"萊卡，你不要喝太多，到時候喝醉又闖禍。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"걱정도 팔자다. 이런 날 안 마시면 언제 마셔?","JPN":"心配性だな。こんな日に飲まずにいつ飲めってんだよ？","ENG":"What are you, my mom? When else will I drink if not today?","TWN":"哎唷，你不要囉嗦啦，此時不喝待何時？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"시원시원해서 좋구만. 마음에 들었어!","JPN":"スカッとしてていいねぇ。気に入った！","ENG":"You speak my language. I like your style!","TWN":"爽快！我喜歡！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"스태프 아가씨도 한 잔 받게! 오늘의 주인공이잖아!","JPN":"スタッフのお嬢ちゃんも一杯やんな！　今日の主人公だろ！","ENG":"Staff girl, I'll pour you a glass! You're the MVP today!","TWN":"駕駛員也喝一杯吧！你是今天的大功臣欸！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아하하…. 아니에요. 다 햄스워스 씨 덕분이죠.","JPN":"あはは……とんでもない。ヘムズワースさんのおかげですよ。","ENG":"Ah hah hah... You're too kind. It was all thanks to you, Mr. Helmsworth.","TWN":"哈哈…沒有啦，都是托你的福。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"보아하니 보통 실력이 아니던데, 채굴 작전에는 관심 없나?","JPN":"見たところかなりの実力だったが、採掘作戦には興味ないか？","ENG":"You got some skills, though. Ever thought about working in the mines?","TWN":"你的能力很好呢，對採礦作戰有興趣嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"괜찮다면 내가 좋은 팀으로 소개시켜 주지.","JPN":"よかったら、ワシがいいチームを紹介してやろう。","ENG":"If you're up for it, I can introduce you to a fantastic team I know.","TWN":"要我替你介紹幾個不錯的隊嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저, 말씀은 감사하지만 저는…….","JPN":"あの、お言葉はありがたいのですが、私は……","ENG":"Uh... Thank you, but I'm...","TWN":"謝謝你的好意，但我……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어이, 할배. 지금 우리 스태프한테 무슨 수작을 부리는 거야?","JPN":"おい、ジジイ。うちのスタッフを何口説いてんだよ？","ENG":"Hey, gramps. You trying to take away our staff?","TWN":"喂，這位阿公！你想對我們的駕駛員做什麼？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"스키너를 데려가면 가만 안 놔둘 줄 알아요.","JPN":"スキナーを連れ出したら許しませんよ。","ENG":"I'll be your worst nightmare if you take Skinner away from us.","TWN":"你要是敢帶走史金納，我可不會放過你。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"너희들…….","JPN":"みんな……","ENG":"Gals...","TWN":"你們……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이거 보기보다 팀원끼리 우정이 꽤 끈끈한데?","JPN":"こりゃあ、意外とチームメンバー同士で仲がいいんだな。","ENG":"Whoa, aren't you like the three musketeers!","TWN":"沒想到你們的友情這麼堅定？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"좋아. 그럼 이 아가씨가 자리를 비운 동안 자네들 함선을 무상으로 수리해 주지.","JPN":"よし。それじゃあ、こっちのお嬢ちゃんがいない間はワシが艦船をタダで修理するというのはどうだ。","ENG":"All right. Then while she's away, I'll repair your ship free of charge.","TWN":"好吧！那她不在的這段時間，我就免費替你們修理艦船吧！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잘 가, 스키너. 가끔은 네 품이 그리울 거야.","JPN":"じゃあな、スキナー。たまにあんたの胸が恋しくなるだろうな。","ENG":"Bye, Skinner. I'll miss you sometimes.","TWN":"史金納拜拜，我偶爾會想念你的懷抱的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"편지 자주 보내요.","JPN":"手紙、送ってくださいね。","ENG":"Send us postcards and letters, okay?","TWN":"要常常寫信回來喔。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"너희들, 적어도 고민하는 척은 해야지!","JPN":"みんな、ちょっとは悩むふりしてよ！","ENG":"Wow, at least pretend to think about it!","TWN":"你們幾個！好歹也假裝替我擔心一下吧！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"하하하핫! 얼마만에 이렇게 크게 웃어보는지 모르겠군.","JPN":"ははははっ！　こんなに大笑いしたのは久しぶりだ。","ENG":"Hahahaha! I can't remember the last time I laughed this hard.","TWN":"哈哈哈哈！我好久沒像這樣大笑了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"햄스워스 씨는 리그 기간 동안 우리 팀 전문 정비사로 도와주기로 했네.","JPN":"ヘムズワース氏はリーグの期間中、このチームの専門整備士として手伝ってくれることになった。","ENG":"Mr. Helmsworth has decided to be our mechanic for the duration of the league.","TWN":"漢姆沃斯說願意在聯賽期間擔任我們隊的維修師，"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 함선은 너무 걱정하지 않아도 돼.","JPN":"だから、艦船のことはあまり心配しなくてもいい。","ENG":"So you don't have to worry too much about the ship.","TWN":"所以艦船的部分不用太擔心。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으으, 또 속았어. 역시 어른들은 다 거짓말쟁이야.","JPN":"うう、また騙された。やっぱり大人はみんな嘘つきだわ。","ENG":"Ngh, fooled again. You adults are all liars.","TWN":"可惡，又被騙了，大人果然都是騙子。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 취했어요? 갑자기 왜 말이 없어요?","JPN":"ライカ、酔ってるの？　いきなり口数が少なくなったけど。","ENG":"Laika, are you drunk? Why are you suddenly so quiet?","TWN":"萊卡，你醉啦？怎麼突然這麼安靜？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니, 별 건 아니야. 신경 쓰지마.","JPN":"いや、別に。気にするな。","ENG":"No, it's nothing. Don't worry about me.","TWN":"沒事，我沒醉，不用管我。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"여러분! 고기 다 구워졌어요! 선착순이니까 빨리 오세요!","JPN":"みなさん！　お肉、焼けましたよ！　早い者勝ちですから早く来てください！","ENG":"Everyone! The meat's all done! It's first come first served, so better come quick!","TWN":"大家！肉都烤好囉！先搶先贏，快來吃喔！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하핫, 역시 대단하네, 코치.","JPN":"ははっ、コーチはやっぱすごいや。","ENG":"Haha, I'm impressed, Coach.","TWN":"哈哈，教練果然厲害。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어떻게 그 꼬장꼬장한 할배를 하루만에 꼬셨대?","JPN":"どうやってあの剛直なジジイを一日で落としたの？","ENG":"How did you manage to persuade that nitpicky grandpa in just a day?","TWN":"你是怎麼在一天之內就搞定那個固執的阿公的？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 꽤 인망이 있는 편이라서 말이지.","JPN":"私は結構人望のある方だからな。","ENG":"I'm pretty popular, you know.","TWN":"可能我做人蠻成功的吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"뭔가 하고 싶은 말이 있는 것 같은데?","JPN":"何が言いたいことがあるようだが。","ENG":"I feel like you have something you want to say to me.","TWN":"你好像想說什麼？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"꼬맹이한테서 직접 들었겠지? 녀석이 결승 진출을 노리는 이유?","JPN":"おこちゃまから聞いたんだろ？　決勝進出を狙う理由。","ENG":"Kid told you herself, didn't she? The reason she wants to go to the final?","TWN":"小鬼應該有跟你說過吧？她想要進入決賽的原因？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그걸 알면서 아무 말 없이 도와주는 거야?","JPN":"それを知りながら、何も言わずに手伝うの？","ENG":"You know, and yet, you're still helping her without saying anything about it?","TWN":"你聽完後二話不說就決定要幫她？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"기본적으로 나는 참견쟁이라네.","JPN":"私は基本的にお節介焼きなのさ。","ENG":"I've always been nosy.","TWN":"其實我這個人蠻雞婆的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"자네가 그 아이를 돕는 이유와 비슷하다고 할 수 있지.","JPN":"君があの子を手伝う理由と同じだよ。","ENG":"It's similar to why you want to help her.","TWN":"我幫她的理由和你差不多。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"손에 닿는 것들도 내버려 둘 만큼 모질지 못해서 말일세.","JPN":"助けられる者を放っておけるほど非情ではないのでね。","ENG":"I'm not cruel enough to ignore things when I can help.","TWN":"無法狠下心來坐視不管。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하지만 꼬맹이를 돕는 다는 건……. ","JPN":"でも、おこちゃまを手伝うってことは…… ","ENG":"But helping her out means...","TWN":"但是，幫那小鬼就表示…… "},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"결국, 누군가를 죽게 할 지도 모른다는 거잖아.","JPN":"結局、誰かを死なせるかもしれないってことだろ？","ENG":"That, eventually, someone might get killed.","TWN":"很可能會有人因此死掉。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 그런 결과를 바라나?","JPN":"君はそのような結果を望んでいるのかい？","ENG":"Is that the result you desire?","TWN":"這是你期待的結果嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……딱히.","JPN":"……別に。","ENG":"...Not really.","TWN":"我……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나는 총알이니까. 방아쇠 쥔 놈이 겨누는 대로 날아갈 뿐이야.","JPN":"私は銃弾だから。引き金を持ってる奴が狙うとおり飛んでいくだけだよ。","ENG":"I'm like a bullet. I just fly in the direction the person who pulls the trigger aims at.","TWN":"我是子彈，拿槍的人指向哪裡，子彈就會往哪裡飛。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"계속 그렇게 살아왔어.","JPN":"ずっとそう生きてきた。","ENG":"That's how I've lived all my life.","TWN":"我一直以來都是這樣。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그때나, 지금이나.","JPN":"あの時も、今も。","ENG":"Back then, and even now.","TWN":"無論是那時候，或是現在。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"미안. 아무래도 좀 취한 모양이네. 쓸데없는 소리를 다 하고.","JPN":"悪い。ちょっと酔ったっぽいな。余計なこと言った。","ENG":"Sorry. I guess I'm a little drunk. I keep saying all this nonsense.","TWN":"抱歉，我好像醉了，才會說這些有的沒的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"방금 건 신경 쓰지 마, 코치! 나도 신경 안 쓸 테니깐!","JPN":"今のは気にするな、コーチ！　私も気にしないから！","ENG":"Never mind what I just told you, Coach! I'll do the same for you too!","TWN":"教練，剛才說的話你別放在心上！我也不會放心上！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"바람 좀 쐬고 올게. 방금 한 말은 잊어, 코치.","JPN":"ちょっと風に当たってくる。今の言葉は忘れて、コーチ。","ENG":"I need to go get some air. Coach, forget what I said here.","TWN":"我去吹吹風，忘了剛才說的話，教練。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"후우, 내가 미쳤나, 진짜.","JPN":"ふう、マジでどうかしてる。","ENG":"Phew... I must really be out of my mind.","TWN":"呼，我在發什麼瘋？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"본선에서 한 번 이긴 걸 갖고 뭘 으스대는 거야. 꼬맹이도 아니고.","JPN":"本戦で一回勝ったくらいで何を調子に乗ってんだ？　ガキじゃあるまいし。","ENG":"Bragging and showing off after winning just one match in the elimination rounds. I acted like the kid.","TWN":"不過在決賽中贏一場而已，是在神氣什麼，又不是小朋友。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……음? 거기 어떤 녀석이야!?","JPN":"……うん？　そこ、誰だ！？","ENG":"...Hmm? Who goes there?!","TWN":"……嗯？誰在那裡！？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>곱슬머리</color>.","JPN":"<color=#ffd34c>縮れ毛</color>。","ENG":"<color=#ffd34c>Curly hair</color>.","TWN":"<color=#ffd34c>自然捲</color>。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"탐사 때 쓰던 호출부호, 맞지?","JPN":"探査の時に使っていたコードネーム、よね？","ENG":"That was your code name during the exploration, was it not?","TWN":"這是探索時使用的行動代號，對吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"네 정체를 알고 있다. 함께 가 줘야겠어.","JPN":"君の正体は知っている。一緒に来てもらうわ。","ENG":"I know who you are. You are coming with me.","TWN":"我知道你是誰，跟我走一趟吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하, 웃기시네. 대뜸 나타나서 한다는 게 그딴 소리냐?","JPN":"は、ふざけんな。いきなり現れて何それ？","ENG":"*Scoff* As if. You suddenly come out of nowhere, and that's what you say to me?","TWN":"哈，笑死人，突然冒出來沒頭沒尾地胡說什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어디 소속인지 몰라도, 그 이름으로 부르는 놈들에게 협조할 생각 같은 건 없어.","JPN":"どこの所属かは知らないけど、その名前で呼ぶ奴らに協力するつもりなんてないね。","ENG":"I don't know what your affiliation is, but I have no intention of helping anyone who calls me by that name.","TWN":"我不知道是誰派你來的，但我沒興趣配合那樣叫我的人。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"두 번 말하게 하지 않았으면 좋겠어.","JPN":"二度も言わせないでほしいわ。","ENG":"Do not make me repeat myself.","TWN":"不要讓我說第二次。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>형제들</color>에게는 네가 봤던 것이 필요해. ","JPN":"<color=#ffd34c>兄弟</color>には君が見たことが必要なの。 ","ENG":"<color=#ffd34c>The Brothers</color> need what you saw up there.","TWN":"<color=#ffd34c>兄弟們</color>需要你看過的東西。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"하나부터 열까지 전부.","JPN":"一から十まで、全部。","ENG":"All of it.","TWN":"把你看到的全盤托出。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아, 그래? 그거라면 내가 여기서도 얼마든지 말해 줄 수 있지.","JPN":"あ、そう？　それならここでいくらでも話してやるよ。","ENG":"Oh, really? Then I can tell you what I saw right here.","TWN":"原來是這樣？那我不用跟你走一趟啦，我直接在這裡說就好。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"개뿔도 없었다. 엿이나 잡수셔.","JPN":"なーんもなかったんだよ。クソくらえ。","ENG":"Nothing. Now go away.","TWN":"我……什麼都沒看到。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 협조하지 않는다면 어쩔 수 없지.","JPN":"いいでしょう。協力しないというなら仕方ないわね。","ENG":"Very well. If you are not willing to cooperate, I have no choice.","TWN":"很好，既然你不肯合作，那就別怪我不客氣了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"큭!? 다리를……!? 뭐가 이렇게 빨라!","JPN":"くっ！？　足が……！？　なんて速さだ！","ENG":"Kgh?! My leg...! How are you that fast?!","TWN":"唔！？我的腳……！？動作好快！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"이제 도주는 못하겠지. 저항한다면, 나머지 팔과 다리도 자르겠다.","JPN":"もう逃げるのは無理よ。抵抗すれば残りの腕と足も斬る。","ENG":"Now, you cannot run. Resist, and I will cut off the rest of your limbs.","TWN":"你現在逃不了了，要是再敢反抗，我就把你其他的手跟腳也砍斷。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"어차피 필요한 건 네 머릿속의 기억뿐.","JPN":"どうせ必要なのは君の頭の中にある記憶だけ。","ENG":"All we need is the memories in your head.","TWN":"反正我需要的是你腦袋裡的記憶，"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"머리만 멀쩡하게 회수하면 되겠지.","JPN":"頭さえ無事に回収できれば十分だろうしね。","ENG":"We just need your head to be uninjured.","TWN":"只要確保你的腦袋沒事就好。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};